mapper.update:
update elderly
set is_deleted = 1,
    update_time = #{updateTime}
where id = #{id}
  and is_deleted = 0

mapper.select:
select e.id, e.user_id as userId, fp.id as familyProfileId, u.username as familyUsername, u.name as familyName, u.phone as familyPhone, e.name, e.gender, e.age, e.phone, e.address, e.dining_point_id as diningPointId, dp.name as diningPointName, e.grid_code as gridCode, e.health_info as healthInfo, e.special_needs as specialNeeds, e.id_card as idCard, e.image, e.create_time as createTime, e.update_time as updateTime, e.is_deleted as isDeleted from elderly e left join dining_point dp on e.dining_point_id = dp.id left join user u on e.user_id = u.id left join family_profile fp on fp.user_id = e.user_id and fp.is_deleted = 0
e.is_deleted = 0
and e.name like concat('%', #{name}, '%')
and e.user_id = #{userId}
and e.grid_code = #{gridCode}
order by e.create_time desc, e.id desc

select * from elderly
is_deleted = 0
and name like concat('%', #{name}, '%')
and user_id = #{userId}
and grid_code = #{gridCode}
order by create_time desc, id desc
